#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

#define MAXV 100000
static Node* nodeMap[MAXV + 1];
static int isChild[MAXV + 1];

Node* getNode(int v) {
    if (nodeMap[v] == NULL) {
        nodeMap[v] = (Node*)malloc(sizeof(Node));
        nodeMap[v]->val = v;
        nodeMap[v]->left = nodeMap[v]->right = NULL;
    }
    return nodeMap[v];
}

int kthLargest(Node* root, int k) {
    Node* stack[10000];
    int top = -1;
    Node* cur = root;
    int cnt = 0;
    while (top != -1 || cur != NULL) {
        while (cur != NULL) {
            stack[++top] = cur;
            cur = cur->right;
        }
        cur = stack[top--];
        cnt++;
        if (cnt == k) return cur->val;
        cur = cur->left;
    }
    return -1; // should never happen for valid k
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        // reset maps for this test case
        memset(nodeMap, 0, sizeof(nodeMap));
        memset(isChild, 0, sizeof(isChild));
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            Node* parent = getNode(p);
            Node* child  = getNode(c);
            if (dir == 'L') parent->left = child; else parent->right = child;
            isChild[c] = 1;
        }
        Node* root = NULL;
        for (int v = 1; v <= MAXV; ++v) {
            if (nodeMap[v] && !isChild[v]) { root = nodeMap[v]; break; }
        }
        int ans = kthLargest(root, K);
        printf("%d\n", ans);
        // free allocated nodes (optional for contest environment)
        for (int v = 1; v <= MAXV; ++v) {
            if (nodeMap[v]) free(nodeMap[v]);
        }
    }
    return 0;
}

