#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left = nullptr;
    Node* right = nullptr;
    Node(int v) : val(v) {}
};

int kthLargest(Node* root, int k) {
    stack<Node*> st;
    Node* cur = root;
    int cnt = 0;
    while (!st.empty() || cur) {
        while (cur) { st.push(cur); cur = cur->right; }
        cur = st.top(); st.pop();
        ++cnt;
        if (cnt == k) return cur->val;
        cur = cur->left;
    }
    return -1; // unreachable for valid k
}

int main() {
