import java.io.*;
import java.util.*;

class Node {
    int val;
    Node left, right;
    Node(int v) { this.val = v; }
}

public class Main {
    private static int kthLargest(Node root, int k) {
        Deque<Node> stack = new ArrayDeque<>();
        Node cur = root;
        int cnt = 0;
        while (!stack.isEmpty() || cur != null) {
            while (cur != null) { stack.push(cur); cur = cur.right; }
            cur = stack.pop();
            cnt++;
            if (cnt == k) return cur.val;
            cur = cur.left;
        }
        return -1; // should not happen
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(p, new Node(p));
                map.putIfAbsent(c, new Node(c));
                Node parent = map.get(p);
                Node child = map.get(c);
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (int val : map.keySet()) if (!childSet.contains(val)) { root = map.get(val); break; }
            int ans = kthLargest(root, K);
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

