#!/usr/bin/env python3
import sys

def kth_largest(root, k):
    stack = []
    cur = root
    cnt = 0
    while stack or cur:
        while cur:
            stack.append(cur)
            cur = cur.right
        cur = stack.pop()
        cnt += 1
        if cnt == k:
            return cur.val
        cur = cur.left
    return None

class Node:
    __slots__ = ('val', 'left', 'right')
    def __init__(self, v):
        self.val = v
        self.left = None
        self.right = None

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        nodes = {}
        children = set()
        for __ in range(N-1):
            p = int(next(it)); c = int(next(it)); d = next(it)
            if p not in nodes:
                nodes[p] = Node(p)
            if c not in nodes:
                nodes[c] = Node(c)
            if d == 'L':
                nodes[p].left = nodes[c]
            else:
                nodes[p].right = nodes[c]
            children.add(c)
        root = None
        for v in nodes:
            if v not in children:
                root = nodes[v]
                break
        ans = kth_largest(root, K)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

