        if (!map.has(v)) map.set(v, new Node(v));
        return map.get(v);
    }
    for (let i = 0; i < N - 1; ++i) {
        const p = parseInt(next(), 10);
        const c = parseInt(next(), 10);
        const dir = next();
        const parent = getNode(p);
        const child = getNode(c);
        if (dir === 'L') parent.left = child; else parent.right = child;
        childSet.add(c);
    }
    let root = null;
    for (let [val, node] of map.entries()) {
        if (!childSet.has(val)) { root = node; break; }
    }
    // reverse inorder iterative
    let stack = [];
    let cur = root;
    let cnt = 0;
    let answer = -1;
    while (stack.length || cur) {
        while (cur) { stack.push(cur); cur = cur.right; }
        cur = stack.pop();
        cnt++;
        if (cnt === K) { answer = cur.val; break; }
        cur = cur.left;
    }
